module top_module(clk, reset, mode, addr, data);input clk, reset, mode; 
 input [2:0] addr; 
 output [3:0] data; 
 (* mem2reg *) 
 reg [3:0] ram [0:7]; 
 assign data = ram[addr]; 
 integer i; 
 always @(posedge clk) begin 
  if (reset) begin 
  for (i=0; i<8; i=i+1) 
  ram[i] <= i; 
  end else 
  if (mode) begin 
  for (i=0; i<8; i=i+1) 
  ram[i] <= ram[i]+1; 
  end else begin 
  ram[addr] <= 0; 
  end 
 end 
 endmodule
